return items.map((item) => {
  const row = item.json || {};
  const folderId = String(row.folder_id || '').trim();
  const folderName = String(row.folder_name || folderId || 'folder').trim();
  const slug = folderName
    .toLowerCase()
    .replace(/[^a-z0-9а-яё]+/gi, '-')
    .replace(/^-+|-+$/g, '')
    .slice(0, 48) || folderId;
  const tableId = String(row.grist_table_id || 'Table1').trim() || 'Table1';
  const docName = `zephyr_${folderId}_${slug}`;
  return {
    json: {
      folder_id: folderId,
      folder_name: folderName,
      folder_path: String(row.folder_path || ''),
      grist_doc_id: row.grist_doc_id ? String(row.grist_doc_id) : '',
      grist_table_id: tableId,
      grist_doc_name: docName
    }
  };
}).filter((item) => item.json.folder_id);

return items.map((item) => ({ json: { ...item.json } })).filter((item) => {
  const id = String(item.json.grist_doc_id || '').trim().toLowerCase();
  return id && id !== 'null' && id !== 'undefined';
});

return items.map((item) => ({
  json: {
    ...item.json,
    request_url: $env.GRIST_PARENT_WORKSPACE_ID
      ? `${$env.GRIST_API_URL}/workspaces/${$env.GRIST_PARENT_WORKSPACE_ID}/docs`
      : `${$env.GRIST_API_URL}/docs`,
    request_body: { name: item.json.grist_doc_name }
  }
})).filter((item) => {
  const id = String(item.json.grist_doc_id || '').trim().toLowerCase();
  return !id || id === 'null' || id === 'undefined';
});

const src = $items('Build_Create_Doc_Request', 0, 0);
return items.map((item, idx) => {
  const base = (src[idx] && src[idx].json) ? src[idx].json : {};
  const response = item.json || {};
  const body = typeof response === 'string'
    ? response
    : (typeof response.body === 'string' ? response.body : response.body || response);
  let docId = '';
  if (typeof body === 'string') {
    const trimmed = body.trim();
    if (trimmed.startsWith('{') || trimmed.startsWith('[')) {
      try {
        const parsed = JSON.parse(trimmed);
        docId = String(parsed.id || parsed.docId || parsed.documentId || parsed?.doc?.id || parsed?.data?.id || parsed.data || '').trim();
      } catch (e) {
        docId = trimmed.replace(/^\"|\"$/g, '').trim();
      }
    } else {
      docId = trimmed.replace(/^\"|\"$/g, '').trim();
    }
  } else if (body && typeof body === 'object') {
    docId = String(body.id || body.docId || body.documentId || body?.doc?.id || body?.data?.id || body.data || '').trim();
  }
  if (!docId || docId.toLowerCase() === 'undefined' || docId.toLowerCase() === 'null') {
    throw new Error(`Failed to create Grist doc for folder ${base.folder_id || 'unknown'}`);
  }
  return { json: {
    ...base,
    grist_doc_id: docId
  }};
});

const esc = (v) => v === null || v === undefined ? 'NULL' : `'${String(v).replace(/'/g, "''")}'`;
return items.map((item) => {
  const row = item.json || {};
  const folderId = String(row.folder_id || '').trim();
  const docId = String(row.grist_doc_id || '').trim();
  const tableId = String(row.grist_table_id || 'Table1').trim() || 'Table1';
  const docName = String(row.grist_doc_name || '');
  if (!folderId || !docId || docId.toLowerCase() === 'undefined' || docId.toLowerCase() === 'null') {
    return null;
  }
  const docUrl = `${$env.GRIST_DOCS_BASE_URL || 'https://docs.getgrist.com'}/${docId}`;
  const sql = `
    INSERT INTO grist_folder_docs (folder_id, grist_doc_id, grist_table_id, grist_doc_name, grist_doc_url, last_synced_at, updated_at)
    VALUES (${esc(folderId)}, ${esc(docId)}, ${esc(tableId)}, ${esc(docName)}, ${esc(docUrl)}, NOW(), NOW())
    ON CONFLICT (folder_id) DO UPDATE SET
      grist_doc_id = EXCLUDED.grist_doc_id,
      grist_table_id = EXCLUDED.grist_table_id,
      grist_doc_name = EXCLUDED.grist_doc_name,
      grist_doc_url = EXCLUDED.grist_doc_url,
      last_synced_at = NOW(),
      updated_at = NOW();
  `;
  return { json: { ...row, folder_id: folderId, grist_doc_id: docId, grist_table_id: tableId, sql_query: sql } };
}).filter((item) => item !== null);

const grouped = new Map();
for (const item of items) {
  const row = item.json || {};
  const cycle = String(row.cycle_name || '').trim();
  const tc = String(row.test_case_name || '').trim();
  const docId = String(row.grist_doc_id || '').trim();
  const tableId = String(row.grist_table_id || 'Table1').trim() || 'Table1';
  const folderId = String(row.folder_id || '').trim();
  if (!cycle || !tc || !docId || !folderId) continue;

  const groupKey = `${folderId}::${docId}::${tableId}`;
  if (!grouped.has(groupKey)) {
    grouped.set(groupKey, {
      folder_id: folderId,
      grist_doc_id: docId,
      grist_table_id: tableId,
      byKey: new Map()
    });
  }

  const recordKey = `${cycle}::${tc}`;
  const trid = String(row.test_result_id || '').trim();
  const objective = String(row.objective || '').trim();
  const objectiveWithId = trid ? `TRID:${trid}${objective ? ' | ' + objective : ''}` : objective;
  grouped.get(groupKey).byKey.set(recordKey, {
    require: { A: cycle, B: tc },
    fields: {
      A: cycle,
      B: tc,
      C: objectiveWithId
    }
  });
}

const out = [];
for (const group of grouped.values()) {
  const records = Array.from(group.byKey.values());
  if (!records.length) continue;
  out.push({
    json: {
      folder_id: group.folder_id,
      grist_doc_id: group.grist_doc_id,
      grist_table_id: group.grist_table_id,
      request_body: { records }
    }
  });
}
return out;

const srcItems = $items('Build_Grist_Rows_Upsert', 0, 0);
const out = [];
const skipped = {
  missing_keys: 0,
  both_checked: 0,
  neither_checked: 0
};

const toBool = (value) => {
  if (value === true || value === 1) return true;
  if (value === false || value === 0 || value === null || value === undefined) return false;
  const normalized = String(value).trim().toLowerCase();
  if (['true', '1', 'yes', 'y', 'on'].includes(normalized)) return true;
  if (['false', '0', 'no', 'n', 'off', ''].includes(normalized)) return false;
  return false;
};

for (let idx = 0; idx < items.length; idx += 1) {
  const src = (srcItems[idx] && srcItems[idx].json) ? srcItems[idx].json : {};
  const payload = items[idx].json || {};
  const records = Array.isArray(payload.records) ? payload.records : [];
  for (const rec of records) {
    const f = rec.fields || {};
    const cycle = String(f.A || '').trim();
    const tc = String(f.B || '').trim();
    const comment = String(f.F || '');
    const objectiveCell = String(f.C || '');
    const tridMatch = objectiveCell.match(/TRID:(\\d+)/);
    const testResultId = tridMatch ? tridMatch[1] : '';
    const done = toBool(f.D);
    const notDone = toBool(f.E);

    if (!cycle || !tc) {
      skipped.missing_keys += 1;
      continue;
    }

    if (done && notDone) {
      skipped.both_checked += 1;
      continue;
    }

    if (!done && !notDone) {
      skipped.neither_checked += 1;
      continue;
    }

    out.push({ json: {
      folder_id: String(src.folder_id || ''),
      cycle_name: cycle,
      test_case_name: tc,
      test_result_id: testResultId,
      desired_status_id: done ? '145' : '146',
      desired_comment: comment
    }});
  }
}

if (skipped.missing_keys || skipped.both_checked || skipped.neither_checked) {
  console.log('[Extract_Operator_Decisions] skipped records', skipped);
}

return out;

const esc = (v) => v === null || v === undefined ? 'NULL' : `'${String(v).replace(/'/g, "''")}'`;
return items.map((item) => {
  const row = item.json || {};
  const byId = String(row.test_result_id || '').trim();
  const whereClause = byId
    ? `tr.test_result_id = ${esc(byId)}`
    : `ru.test_run_id = tr.test_run_id AND ru.folder_id = ${esc(row.folder_id)} AND ru.run_name = ${esc(row.cycle_name)} AND tr.test_case_name = ${esc(row.test_case_name)}`;
  const fromClause = byId ? '' : 'FROM test_runs ru';
  const sql = `
    UPDATE test_results tr
    SET desired_status_id = ${esc(row.desired_status_id)},
        desired_comment = ${esc(row.desired_comment || '')},
        updated_at = NOW()
    ${fromClause}
    WHERE ${whereClause}
      AND (tr.desired_status_id IS DISTINCT FROM ${esc(row.desired_status_id)}
           OR tr.desired_comment IS DISTINCT FROM ${esc(row.desired_comment || '')});
  `;
  return { json: { ...row, sql_query: sql } };
});

const srcItems = $items('Build_Save_Doc_Map_SQL', 0, 0);
return items.map((item, idx) => {
  const src = (srcItems[idx] && srcItems[idx].json) ? srcItems[idx].json : {};
  return {
    json: {
      folder_id: String(src.folder_id || ''),
      grist_doc_id: String(src.grist_doc_id || ''),
      grist_table_id: String(src.grist_table_id || 'Table1') || 'Table1',
      grist_doc_name: String(src.grist_doc_name || '')
    }
  };
}).filter((item) => item.json.folder_id && item.json.grist_doc_id);
